// "未去過" suggestion orchestration (client side).
//  ① own 👍 in the district (free, moat)  ② taste-filter FEHD → tight candidates
//  (free)  ③ Google-check + Haiku synth via /suggest (Phase B)  ④ honest source.
// Cache stores DERIVED facts only (place_id + rating bucket) → same-area re-ask is
// free (template, no Google/Haiku). Falls back to Phase A (names, "未查評價") when
// there's no endpoint or the cap is hit.
import type { Catalogue, Memory, Retrieved } from "./types";
import type { RecallResult } from "./recall";
import { areaInQuery } from "./catalogue";
import { deriveTasteProfile, filterByTaste, keywordsForTags, cuisineInQuery } from "./taste";
import { getTasteSeed, getHomeAreas } from "./onboarding";
import { districtZh } from "./fehd";

const RECALL = (import.meta.env.VITE_RECALL_ENDPOINT as string | undefined) || "";
const ENDPOINT = RECALL ? RECALL.replace(/\/recall$/, "/suggest") : "";

const CACHE_KEY = "dm.suggestCache";
const TTL = 7 * 86400 * 1000;
const SOURCE = "（基於 Google 評價 + 你口味，唔係你自己試過）";

interface CachedCand { name: string; tag: string; ratingBucket: string | null; placeId: string }

function cacheGet(key: string): CachedCand[] | null {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    const e = all[key];
    if (e && Date.now() - e.ts < TTL) return e.cands;
  } catch { /* ignore */ }
  return null;
}
function cacheSet(key: string, cands: CachedCand[]): void {
  try {
    const all = JSON.parse(localStorage.getItem(CACHE_KEY) || "{}");
    all[key] = { ts: Date.now(), cands };
    localStorage.setItem(CACHE_KEY, JSON.stringify(all));
  } catch { /* ignore */ }
}

export async function buildSuggestion(
  query: string,
  memories: Memory[],
  cat: Catalogue
): Promise<RecallResult | null> {
  // Area: from the query, else fall back to the user's home district (onboarding).
  const home = getHomeAreas();
  const hit = areaInQuery(query) ?? (home.length ? { area: home[0], name: districtZh(home[0]) } : null);
  if (!hit) return null;

  const baseProfile = deriveTasteProfile(memories);
  // Merge the onboarding taste seed so a fresh user's stated tastes count too.
  const liked = [...new Set([...getTasteSeed(), ...baseProfile.liked])];
  const visited = new Set(memories.map((m) => m.restaurantId));

  // In-the-moment condition the user TYPED takes priority (「想食日本嘢」→ 日式),
  // even if never logged. Otherwise use the (memory + seed) taste profile.
  const queryTags = cuisineInQuery(query);
  const useTags = queryTags.length ? queryTags : liked;
  const effProfile = { liked: useTags, disliked: baseProfile.disliked, keywords: keywordsForTags(useTags) };

  // ① own record in this district: 👍 first, else onboarding "常去".
  const ownGood = memories.filter((m) => m.area === hit.area && m.dishes.some((d) => d.rating === "good"));
  const ownSeed = memories.filter((m) => m.area === hit.area && m.source === "onboarding" && !ownGood.includes(m));
  const ownCited: Retrieved[] = [...ownGood, ...ownSeed].slice(0, 3).map((m) => ({ memory: m, score: 1, relevance: 1 }));
  const ownLine = ownGood.length
    ? `你喺「${hit.name}」👍 過：${[
        ...new Set(ownGood.flatMap((m) => m.dishes.filter((d) => d.rating === "good").map((d) => `${m.restaurantName}嘅${d.name}`))),
      ].slice(0, 3).join("、")}。`
    : ownSeed.length
      ? `你話你常去「${hit.name}」嘅：${[...new Set(ownSeed.map((m) => m.restaurantName))].slice(0, 3).join("、")}。`
      : "";

  // ② taste-filter FEHD → tight candidates (priority: the in-query condition)
  const candidates = filterByTaste(cat, hit.area, effProfile, visited, 5);
  if (!ownGood.length && !ownSeed.length && !candidates.length) return null; // nothing → FEHD-counts fallback

  const key = `${hit.area}|${useTags.slice(0, 4).join(",")}`;
  const compose = (body: string): RecallResult => ({
    kind: "recommend",
    cited: ownCited,
    text: [ownLine, body].filter(Boolean).join("\n\n"),
  });

  // Cache hit → template, no Google/Haiku spend.
  const cached = cacheGet(key);
  if (cached) {
    const good = cached.filter((c) => c.ratingBucket === "高" || c.ratingBucket === "中");
    if (good.length) {
      return compose(`未去過就試吓 ${SOURCE}：\n${good.map((c) => `・${c.name}（${c.tag}，評價${c.ratingBucket}）`).join("\n")}`);
    }
  }

  // ③ Phase B — server Google-checks candidates + Haiku synth.
  if (ENDPOINT && candidates.length) {
    try {
      const payload = {
        query,
        tags: useTags.slice(0, 6),
        candidates: candidates.map((c) => ({ name: c.r.name.tc || c.r.name.en, addr: c.r.addr, area: c.r.area, tag: c.tag })),
      };
      const res = await fetch(ENDPOINT, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(payload),
        signal: AbortSignal.timeout(22000), // Render cold start → fall back to Phase A
      });
      if (res.ok) {
        const data = await res.json();
        if (Array.isArray(data.facts)) {
          cacheSet(key, data.facts.filter((f: { placeId?: string }) => f.placeId).map((f: { name: string; ratingBucket: string | null; placeId: string }) => ({
            name: f.name,
            tag: candidates.find((c) => (c.r.name.tc || c.r.name.en) === f.name)?.tag || "",
            ratingBucket: f.ratingBucket,
            placeId: f.placeId,
          })));
        }
        if (data.ok && data.matched && typeof data.text === "string" && data.text.trim()) {
          return compose(data.text.trim());
        }
      }
    } catch { /* fall through to Phase A */ }
  }

  // ④ Phase A fallback — taste-matched names, honestly "未查評價".
  const paText = candidates.length
    ? `未去過，基於你口味（未查評價）可以試吓：\n${candidates.slice(0, 4).map((c) => `・${c.r.name.tc}（${c.tag}）`).join("\n")}`
    : "";
  const out = compose(paText);
  return out.text ? out : null;
}
