// New-user onboarding (zero-AI, 100% on-device). 3 short steps → initial taste
// profile (dm.tasteSeed), home districts (dm.homeAreas), and a few seed memories
// so day-1 isn't a blank book. Every step is skippable; "跳過，直接開始" exits.
import type { Catalogue, Restaurant } from "./types";
import { el, clear } from "./dom";
import { searchRestaurants } from "./catalogue";
import { addMemory, memoryCount } from "./memory";
import { districtZh } from "./fehd";

const K_TASTE = "dm.tasteSeed";
const K_AREAS = "dm.homeAreas";
const K_DONE = "dm.onboarded";

export function getTasteSeed(): string[] {
  try { return JSON.parse(localStorage.getItem(K_TASTE) || "[]"); } catch { return []; }
}
export function getHomeAreas(): string[] {
  try { return JSON.parse(localStorage.getItem(K_AREAS) || "[]"); } catch { return []; }
}
/** Show onboarding only to a brand-new user who hasn't been through it. */
export function needsOnboarding(): boolean {
  return memoryCount() === 0 && !localStorage.getItem(K_DONE);
}
export function markOnboarded(v: "done" | "skipped"): void {
  try { localStorage.setItem(K_DONE, v); } catch { /* ignore */ }
}

// Chip label → stored taste tag (tags align with CUISINE_MAP so they drive the
// FEHD filter; 清淡 is a dimension we keep but don't filter on).
const TASTE_CHIPS: [string, string][] = [
  ["辣", "辣"], ["清淡", "清淡"], ["日式", "日式"], ["港式", "茶餐廳"], ["火鍋", "火鍋"],
  ["點心", "點心"], ["米線", "米線"], ["燒味", "燒味"], ["海鮮", "海鮮"], ["西式", "西式"],
  ["韓國菜", "韓"], ["泰國菜", "泰"], ["甜品", "甜品"], ["咖啡", "咖啡"],
];

const AREA_GROUPS: [string, string[]][] = [
  ["港島", ["Central/Western", "Wan Chai", "Eastern", "Southern"]],
  ["九龍", ["Yau Tsim", "Mong Kok", "Sham Shui Po", "Kowloon City", "Wong Tai Sin", "Kwun Tong"]],
  ["新界", ["Kwai Tsing", "Tsuen Wan", "Sha Tin", "Tai Po", "Sai Kung", "Tuen Mun", "Yuen Long", "North", "Islands"]],
];

/** Render the onboarding flow into #app; calls onDone() when finished/skipped. */
export function renderOnboarding(cat: Catalogue, onDone: () => void): void {
  const app = document.getElementById("app")!;
  const taste = new Set<string>();
  const areas = new Set<string>();
  const picks: Restaurant[] = [];
  let step = 0;

  const finish = (): void => {
    const hasData = taste.size > 0 || areas.size > 0 || picks.length > 0;
    if (taste.size) localStorage.setItem(K_TASTE, JSON.stringify([...taste]));
    if (areas.size) localStorage.setItem(K_AREAS, JSON.stringify([...areas]));
    for (const r of picks) {
      addMemory({
        ts: Date.now(), restaurantId: r.id, restaurantName: r.name.tc || r.name.en,
        area: r.area, dishes: [], tasteTags: [], source: "onboarding", confidence: 1,
      });
    }
    markOnboarded(hasData ? "done" : "skipped");
    onDone();
  };

  const chip = (label: string, on: boolean, onclick: () => void) =>
    el("button", { class: "ob2-chip" + (on ? " on" : ""), text: label, onclick });

  const shell = (title: string, sub: string, ...body: (HTMLElement | null)[]) =>
    el("section", { class: "ob2" },
      el("button", { class: "ob2-exit", text: "跳過，直接開始 ›", onclick: finish }),
      el("div", { class: "ob2-steps", text: `第 ${step + 1} / 3 步` }),
      el("h2", { class: "ob2-title", text: title }),
      el("p", { class: "ob2-sub", text: sub }),
      ...body
    );

  const render = (): void => {
    clear(app);
    app.appendChild(step === 0 ? stepTaste() : step === 1 ? stepAreas() : stepRestaurants());
    window.scrollTo(0, 0);
  };

  function stepTaste(): HTMLElement {
    const grid = el("div", { class: "ob2-chips" });
    const draw = () => {
      clear(grid);
      for (const [label, tag] of TASTE_CHIPS)
        grid.appendChild(chip(label, taste.has(tag), () => { taste.has(tag) ? taste.delete(tag) : taste.add(tag); draw(); }));
    };
    draw();
    return shell("你鍾意食咩？", "揀返啱你嘅（可多選，摸個底就得）。", grid,
      el("div", { class: "ob2-nav" },
        el("button", { class: "ob2-next", text: "下一步", onclick: () => { step = 1; render(); } })
      )
    );
  }

  function stepAreas(): HTMLElement {
    const wrap = el("div", {});
    const draw = () => {
      clear(wrap);
      for (const [region, list] of AREA_GROUPS) {
        wrap.appendChild(el("p", { class: "ob2-group", text: region }));
        const g = el("div", { class: "ob2-chips" });
        for (const a of list)
          g.appendChild(chip(districtZh(a), areas.has(a), () => {
            if (areas.has(a)) areas.delete(a);
            else if (areas.size < 3) areas.add(a);
            draw();
          }));
        wrap.appendChild(g);
      }
    };
    draw();
    return shell("你成日喺邊區出沒？", "揀 1–3 個區，之後幫你就近搵。", wrap,
      el("div", { class: "ob2-nav" },
        el("button", { class: "ob2-back", text: "‹ 返", onclick: () => { step = 0; render(); } }),
        el("button", { class: "ob2-skip", text: "跳過呢步", onclick: () => { step = 2; render(); } }),
        el("button", { class: "ob2-next", text: "下一步", onclick: () => { step = 2; render(); } })
      )
    );
  }

  function stepRestaurants(): HTMLElement {
    const chosen = el("div", { class: "ob2-picks" });
    const results = el("div", { class: "ob2-results" });
    const input = el("input", { class: "ob2-search", type: "search", placeholder: "搜餐廳名或地區…", autocomplete: "off" }) as HTMLInputElement;
    const finishBtn = el("button", { class: "ob2-next", text: "完成" }) as HTMLButtonElement;
    const refreshFinish = () => { finishBtn.textContent = picks.length ? `完成（加 ${picks.length} 間）` : "完成"; };
    const drawChosen = () => {
      clear(chosen);
      for (const r of picks)
        chosen.appendChild(el("button", { class: "ob2-pick", text: `${r.name.tc} ✕`, onclick: () => { picks.splice(picks.indexOf(r), 1); drawChosen(); refreshFinish(); } }));
    };
    input.addEventListener("input", () => {
      clear(results);
      if (!input.value.trim()) return;
      let list = searchRestaurants(cat, input.value, 10);
      if (areas.size) list = [...list].sort((a, b) => Number(areas.has(b.area)) - Number(areas.has(a.area)));
      for (const r of list.slice(0, 6)) {
        if (picks.some((p) => p.id === r.id)) continue;
        results.appendChild(el("button", { class: "ob2-result", text: `${r.name.tc}　·　${districtZh(r.area)}`, onclick: () => {
          if (picks.length < 5 && !picks.some((p) => p.id === r.id)) { picks.push(r); drawChosen(); refreshFinish(); input.value = ""; clear(results); input.focus(); }
        } }));
      }
    });
    finishBtn.onclick = finish;
    drawChosen();
    return shell("有邊 3–5 間常去嘅？", "揀咗會即刻入做你嘅記憶，day-1 就唔係空簿（唔使評分）。", chosen, input, results,
      el("div", { class: "ob2-nav" },
        el("button", { class: "ob2-back", text: "‹ 返", onclick: () => { step = 1; render(); } }),
        el("button", { class: "ob2-skip", text: "跳過", onclick: finish }),
        finishBtn
      )
    );
  }

  render();
}
